import { describe, expect, it } from 'vitest';
import { existsSync, mkdtempSync, readFileSync, rmSync, writeFileSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';
import {
  providerInstructionsFileName,
  providerInstructionsPath,
  readExistingProviderInstructions,
  writeProviderInstructionsAtomic,
} from './agents-md-writer.ts';

function tempRepo(): string {
  return mkdtempSync(join(tmpdir(), 'onboard-writer-'));
}

describe('providerInstructionsFileName', () => {
  it('returns CLAUDE.md for claude', () => {
    expect(providerInstructionsFileName('claude')).toBe('CLAUDE.md');
  });
  it('returns .github/copilot-instructions.md for copilot', () => {
    expect(providerInstructionsFileName('copilot')).toBe('.github/copilot-instructions.md');
  });
});

describe('providerInstructionsPath', () => {
  it('roots claude path at CLAUDE.md', () => {
    expect(providerInstructionsPath('/tmp/r', 'claude')).toBe(join('/tmp/r', 'CLAUDE.md'));
  });
  it('roots copilot path under .github/', () => {
    expect(providerInstructionsPath('/tmp/r', 'copilot')).toBe(join('/tmp/r', '.github', 'copilot-instructions.md'));
  });
});

describe('writeProviderInstructionsAtomic', () => {
  it('writes CLAUDE.md with content and ralphctl marker for claude', () => {
    const repo = tempRepo();
    try {
      const { path } = writeProviderInstructionsAtomic(repo, '# Hello\n\nbody.', 'claude');
      expect(path).toBe(join(repo, 'CLAUDE.md'));
      const body = readFileSync(path, 'utf-8');
      expect(body).toContain('# Hello');
      expect(body).toContain('<!-- managed by ralphctl onboard -->');
    } finally {
      rmSync(repo, { recursive: true, force: true });
    }
  });

  it('creates .github/ parent dir and writes copilot instructions', () => {
    const repo = tempRepo();
    try {
      const { path } = writeProviderInstructionsAtomic(repo, '# Copilot', 'copilot');
      expect(path).toBe(join(repo, '.github', 'copilot-instructions.md'));
      expect(existsSync(join(repo, '.github'))).toBe(true);
      const body = readFileSync(path, 'utf-8');
      expect(body).toContain('# Copilot');
      expect(body).toContain('<!-- managed by ralphctl onboard -->');
    } finally {
      rmSync(repo, { recursive: true, force: true });
    }
  });

  it('overwrites previous content atomically', () => {
    const repo = tempRepo();
    try {
      writeProviderInstructionsAtomic(repo, '# First', 'claude');
      writeProviderInstructionsAtomic(repo, '# Second', 'claude');
      const body = readFileSync(join(repo, 'CLAUDE.md'), 'utf-8');
      expect(body).toContain('# Second');
      expect(body).not.toContain('# First');
    } finally {
      rmSync(repo, { recursive: true, force: true });
    }
  });
});

describe('readExistingProviderInstructions', () => {
  it('returns content=null when the file is missing', () => {
    const repo = tempRepo();
    try {
      const result = readExistingProviderInstructions(repo, 'claude');
      expect(result.content).toBeNull();
      expect(result.authored).toBe(false);
    } finally {
      rmSync(repo, { recursive: true, force: true });
    }
  });

  it('marks authored=true when the file lacks the ralphctl marker', () => {
    const repo = tempRepo();
    try {
      writeFileSync(join(repo, 'CLAUDE.md'), '# User wrote this\n');
      const result = readExistingProviderInstructions(repo, 'claude');
      expect(result.content).toContain('User wrote this');
      expect(result.authored).toBe(true);
    } finally {
      rmSync(repo, { recursive: true, force: true });
    }
  });

  it('marks authored=false when the file was generated by ralphctl', () => {
    const repo = tempRepo();
    try {
      writeProviderInstructionsAtomic(repo, '# Auto-generated', 'claude');
      const result = readExistingProviderInstructions(repo, 'claude');
      expect(result.authored).toBe(false);
    } finally {
      rmSync(repo, { recursive: true, force: true });
    }
  });

  it('reads copilot instructions from .github/', () => {
    const repo = tempRepo();
    try {
      writeProviderInstructionsAtomic(repo, '# Copilot-managed', 'copilot');
      const result = readExistingProviderInstructions(repo, 'copilot');
      expect(result.content).toContain('Copilot-managed');
      expect(result.authored).toBe(false);
    } finally {
      rmSync(repo, { recursive: true, force: true });
    }
  });
});
